script:
frappe.ui.form.on("Sales Invoice", {
    refresh: function(frm) {
        // Solo en facturas de devolución ya contabilizadas
        if (frm.doc.is_return && frm.doc.docstatus === 1) {
            frm.add_custom_button(__("Convertir a Vale"), function() {
                convertirAPagoVale(frm);
            }, __("Pago"));
        }
    }
});

function convertirAPagoVale(frm) {
    // Calcular total en positivo (el return tiene valores negativos)
    var total = Math.abs(frm.doc.grand_total || 0);
    if (total <= 0) {
        frappe.msgprint(__("El total de la factura es 0. No se puede convertir."));
        return;
    }

    frappe.confirm(
        "Se va a cambiar el método de pago de " +
        "esta devolución a <strong>Vale</strong> por importe de " +
        "<strong>" + format_currency(total, frm.doc.currency) + "</strong>." +
        "<br><br>¿Continuar?",
        function() {
            // Obtener payments actuales
            var payments = frm.doc.payments || [];
            var nuevosPayments = [];

            // Reemplazar cada payment con Vale
            payments.forEach(function(p, idx) {
                nuevosPayments.push({
                    "name": p.name,
                    "mode_of_payment": "Vale",
                    "amount": idx === 0 ? total : 0,
                    "base_amount": idx === 0 ? total : 0,
                    "default": idx === 0 ? 1 : 0,
                    "type": "General"
                });
            });

            // Si no hay payments, crear uno
            if (nuevosPayments.length === 0) {
                nuevosPayments.push({
                    "mode_of_payment": "Vale",
                    "amount": total,
                    "base_amount": total,
                    "default": 1
                });
            }

            // Guardar
            frm.set_value("payments", nuevosPayments);
            frm.save("Update");
        }
    );
}

frappe.listview_settings["Sales Invoice"] = {
    add_fields: ["is_return", "docstatus"],
    get_indicator: function(doc) {
        // No modificar indicador, solo añadir botón
    },
    button: {
        show: function(doc) {
            return doc.is_return && doc.docstatus === 1;
        },
        get_label: function() {
            return "Convertir a Vale";
        },
        get_description: function(doc) {
            return "Cambia el pago de esta devolución a Vale";
        },
        action: function(doc) {
            frappe.call({
                method: "frappe.client.get",
                args: {
                    doctype: "Sales Invoice",
                    name: doc.name
                },
                callback: function(r) {
                    if (!r || !r.message) return;
                    var frm = { doc: r.message };
                    // Reutilizar la misma lógica
                    convertirValeFromList(frm, doc.name);
                }
            });
        }
    }
};

function convertirValeFromList(frm, docName) {
    var total = Math.abs(frm.doc.grand_total || 0);
    if (total <= 0) {
        frappe.msgprint("El total es 0. No se puede convertir.");
        return;
    }

    frappe.confirm(
        "¿Convertir <strong>" + docName + "</strong> a pago con Vale " +
        "por <strong>" + format_currency(total, frm.doc.currency) + "</strong>?",
        function() {
            var payments = frm.doc.payments || [];
            var nuevosPayments = [];

            payments.forEach(function(p, idx) {
                nuevosPayments.push({
                    "name": p.name,
                    "mode_of_payment": "Vale",
                    "amount": idx === 0 ? total : 0,
                    "base_amount": idx === 0 ? total : 0,
                    "default": idx === 0 ? 1 : 0
                });
            });

            if (nuevosPayments.length === 0) {
                nuevosPayments.push({
                    "mode_of_payment": "Vale",
                    "amount": total,
                    "base_amount": total,
                    "default": 1
                });
            }

            frappe.call({
                method: "frappe.client.set_value",
                args: {
                    doctype: "Sales Invoice",
                    name: docName,
                    fieldname: "payments",
                    value: nuevosPayments
                },
                callback: function(r2) {
                    frappe.msgprint("✅ Factura " + docName +
                        " convertida a Vale por " +
                        format_currency(total, frm.doc.currency));
                    // Recargar la vista de lista
                    frappe.ui.toolbar.clear_cache();
                    cur_list && cur_list.refresh();
                }
            });
        }
    );
}
